  ('medical-tech-moex-09876', 'medical-tech', 'medical-tech-moex-104-bccd9a5a', 'sub-medical-tech-05', NULL, 'single_choice', '有關細菌Catalase test之敘述，下列何者錯誤？', '["以3%雙氧水為試劑", "多數嗜氧及兼性厭氧菌呈陽性反應，但Streptococcaceae呈陰性", "宜選18～24小時培養菌作試驗，並避免使用白金接種環，以免造成偽陽性", "若BAP上欲測試之菌落太小，可將試劑滴在菌落上，見到冒泡泡現象即為陽性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b5e5fcedaca8", "answer_pdf_sha1": "8486a222e764", "source_family": "moex-gov-tw", "moex": {"exam_code": "104020", "c": "311", "s": "44", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學與臨床微生物學（包括細菌與黴菌）", "year": "104", "exam_name": "104年第一次專技牙醫師藥師分階段考試藥師醫檢師醫放師助產師物理治療師職能呼吸治療師獸醫師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
